args.sparql:
SELECT ?chef ?chefLabel WHERE {
  ?restaurant wdt:P1315 3 .
  ?restaurant wdt:P585 ?starDate .
  FILTER (YEAR(?starDate) = 2020) .
  ?restaurant wdt:P1198 ?chef .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

